// // This module is designed to compare two 8-bit input values, A and B.
// It outputs three signals: A_greater (low if A > B), A_equal (low if A == B), and A_less (low if A < B).

module Comparator8Bit (
    input [7:0] A,
    input [7:0] B,
    output reg A_greater,
    output reg A_equal,
    output reg A_less
);

always @(*) begin
    if (A > B) begin
        A_greater = 1;
        A_equal = 0;
        A_less = 0;
    end else if (A < B) begin
        A_greater = 0;
        A_equal = 0;
        A_less = 1;
    end else begin
        A_greater = 0;
        A_equal = 1;
        A_less = 0;
    end
end

endmodule
